// Build HTML Summary Email
const raw = $input.first().json;
const rows = Array.isArray(raw) ? raw : (Array.isArray(raw.body) ? raw.body : [raw]);
const conv = rows[0] || {};

// Extract contact from nested join
const contact = conv.contacts || {};
const contactName = contact.name || contact.phone || 'Onbekend';
const contactPhone = contact.phone || '';

const conversationId = conv.id || '';
const collectedAddress = conv.collected_address || '-';
const collectedWishes = conv.collected_wishes || '-';
const collectedDimensions = conv.collected_dimensions || '-';
const collectedPhone = conv.collected_phone || 'NIET OPGEGEVEN';
const photosCount = Array.isArray(conv.collected_photos) ? conv.collected_photos.length : 0;

const now = new Date();
const dateStr = now.toLocaleDateString('nl-NL', { year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit' });

const html = `<!DOCTYPE html>
<html>
<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px;">

  <div style="background: #16a34a; padding: 20px; border-radius: 8px 8px 0 0;">
    <h1 style="color: white; margin: 0; font-size: 22px;">✅ Nieuwe Lead Gekwalificeerd</h1>
    <p style="color: #dcfce7; margin: 8px 0 0 0;">Via WhatsApp — ${dateStr}</p>
  </div>

  <div style="background: #f0fdf4; padding: 20px; border: 1px solid #86efac; border-top: none;">

    <h2 style="color: #15803d; margin-top: 0;">Contactgegevens</h2>
    <table style="width: 100%; border-collapse: collapse;">
      <tr><td style="padding: 8px; font-weight: bold; width: 130px;">Naam:</td>
          <td style="padding: 8px;">${contactName}</td></tr>
      <tr style="background: white;">
          <td style="padding: 8px; font-weight: bold;">📞 Telefoon:</td>
          <td style="padding: 8px;"><strong style="color: #16a34a; font-size: 16px;">${collectedPhone}</strong></td></tr>
      <tr><td style="padding: 8px; font-weight: bold;">WhatsApp:</td>
          <td style="padding: 8px;">${contactPhone}</td></tr>
    </table>

    <h2 style="color: #15803d; margin-top: 20px;">Project Details</h2>
    <table style="width: 100%; border-collapse: collapse;">
      <tr><td style="padding: 8px; font-weight: bold; width: 130px;">Adres:</td>
          <td style="padding: 8px;">${collectedAddress}</td></tr>
      <tr style="background: white;">
          <td style="padding: 8px; font-weight: bold;">Wensen:</td>
          <td style="padding: 8px;">${collectedWishes}</td></tr>
      <tr><td style="padding: 8px; font-weight: bold;">Afmetingen:</td>
          <td style="padding: 8px;">${collectedDimensions}</td></tr>
      <tr style="background: white;">
          <td style="padding: 8px; font-weight: bold;">Foto's:</td>
          <td style="padding: 8px;">${photosCount} ontvangen</td></tr>
    </table>

    <div style="margin-top: 20px; padding: 15px; background: #fef9c3; border-radius: 6px; border: 1px solid #fde047;">
      <strong>📞 Actie vereist:</strong> Bel ${contactName} op 
      <strong>${collectedPhone !== 'NIET OPGEGEVEN' ? collectedPhone : contactPhone}</strong> om een afspraak in te plannen.
    </div>
  </div>

  <div style="background: #f8fafc; padding: 12px 20px; border: 1px solid #e2e8f0; border-top: none; border-radius: 0 0 8px 8px;">
    <p style="color: #94a3b8; font-size: 12px; margin: 0;">
      Automatisch gegenereerd door Chattie | Gesprek ID: ${conversationId}
    </p>
  </div>

</body>
</html>`;

return [{
  json: {
    html: html,
    contactName: contactName,
    contactPhone: contactPhone,
    conversationId: conversationId,
    emailSubject: `✅ Nieuwe Lead: ${contactName}`
  }
}];

// Error Handler
const error = $input.first().json;
return [{
  json: {
    type: 'error',
    description: String(error.message || error.error || 'Unknown error').substring(0, 500),
    metadata: { workflow: 'qualification-summary', node: error.node || 'Unknown', timestamp: new Date().toISOString() }
  }
}];
